table.ejecuta:
 if( 'fiscal' == '1' ) 
{
		_end_transaction();
		loger('Ticket ------------- id_regmovim', 'updatessql.log');
		_begin_transaction();
		$printer = 'printer_fiscal_pos';
		loger('Emito Ticket', 'updatessql.log');
		ob_start();
		echo "Generando ticket.. id_regmovim";
		$calculo = new EmiteFiscal();
		$calculo->setPrinter($printer);
		$calculo->imprimir('id_regmovim');
		echo "Fin";
		$salida = ob_get_contents();
		ob_end_clean();
		loger($salida, 'updatessql.log');
}
